+fn check_refresh_cooldown(
+    most_recent_refresh_ms: i64,
+    now_ms_val: i64,
+    cooldown_ms: i64,
+) -> Option<(i64, i64)> {
+    if most_recent_refresh_ms <= 0 {
+        return None;
+    }
+    let elapsed = now_ms_val - most_recent_refresh_ms;
+    if elapsed < cooldown_ms {
+        Some((elapsed / 1000, (cooldown_ms - elapsed) / 1000))
+    } else {
+        None
+    }
+}
