+fn resolve_alt_screen_state(state: &IpcPaneState) -> Option<bool> {
+    if !state.known {
+        return None;
+    }
+    if let Some(cursor_state) = state.cursor_alt_screen {
+        return Some(cursor_state);
+    }
+    if state.last_status_at.is_some() {
+        return state.alt_screen;
+    }
+    None
+}
